414	exports.cryptPassword = async (password) => {
415	  const hashedPassword = await new Promise((resolve, reject) => {
416	    bcrypt.hash(password, 10, function (err, hash) {
417	      if (err) reject(err)
418	      resolve(hash)
419	    });
420	  })
421	  return hashedPassword
422	}
