424	exports.comparePassword = async (plainPass, hashword) => {
425	  const hashedPassword = await new Promise((resolve, reject) => {
426	    bcrypt.compare(plainPass, hashword, function (err, isPasswordMatch) {
427	      if (err) {
428	        reject(err)
429	      } else {
430	        resolve(isPasswordMatch)
431	      }
432	    });
433	  })
434	  return hashedPassword
435	};
