863	exports.mapSTDItems = async (prodItems, userRole) => {
864	  return (function () {
865	    let items = [];
866	    let prodItem = prodItems[0].dataValues;
867	    for (var i = 0; prodItem.StandardizedGroups.length > i; i++) {
868	      let stdGroup = prodItem.StandardizedGroups[i].dataValues;
869	      for (var j = 0; stdGroup.StandardizedSizes.length > j; j++) {
870	        items.push({});
871	        items[items.length - 1]['prod_name'] = prodItems[0].dataValues.prod_name;
872	        items[items.length - 1]['prod_id'] = prodItems[0].dataValues.id
873	        items[items.length - 1]['std_group'] = stdGroup.title;
874	        let stdSize = stdGroup.StandardizedSizes[j].dataValues;
875	        items[items.length - 1]['row_id'] = stdSize.id + '_' + stdGroup.id;
876	        items[items.length - 1]['size_cm'] = stdSize.itemSizeCm.dataValues.itemSize_title;
877	        items[items.length - 1]['size_in'] = stdSize.itemSizeIn.dataValues.itemSize_title;
878	        items[items.length - 1]['stdSize_id'] = stdSize.id;
879	        items[items.length - 1]['stdGroup_id'] = stdGroup.id;
880	        items[items.length - 1]['item_status'] = stdSize.status;
881	        items[items.length - 1]['highlighted'] = [];
882	
883	        for (var k = 0; stdSize.StandardizedDetails.length > k; k++) {
884	          let stdDetail = stdSize.StandardizedDetails[k].dataValues;
885	
886	          for (var m = 0; stdDetail.StandardizedVendors.length > m; m++) {
887	
888	            if (stdDetail.StandardizedVendors[m].dataValues.highlighted) {
889	              items[items.length - 1]['highlighted'].push(`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}_${stdDetail.StandardizedVendors[m].dataValues.highlighted}`);
890	            }
891	
892	            if (userRole == 'vendor') {
893	              items[items.length - 1]['width'] = stdDetail.StandardizedVendors[m].dataValues.width;
894	              items[items.length - 1]['height'] = stdDetail.StandardizedVendors[m].dataValues.height;
895	              items[items.length - 1]['length'] = stdDetail.StandardizedVendors[m].dataValues.length;
896	            }
897	            if (userRole == 'admin' || userRole == 'production' || userRole == 'vendor') {
898	              items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = stdDetail.StandardizedVendors[m].dataValues.price;
899	            } else {
900	              if (stdDetail.StandardizedVendors[m].dataValues.price) {
901	                items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = true;
902	              } else {
903	                items[items.length - 1][`${prodItem.id}_${stdDetail.StandardizedVersion.dataValues.id}_${stdDetail.StandardizedVendors[m].dataValues.factory_id_fk}`] = false;
904	              }
905	            }
906	          }
907	        }
908	        if (userRole == 'vendor') {
909	          if (items[items.length - 1]['highlighted'].length == 0) {
910	            items.splice(items.length - 1, 1);
911	          }
912	        }
913	      }
914	    }
915	    return items;
