1494	          quote_date: new Date().toISOString(),
1495	        }
1496	      });
1497	
1498	      if (created) {
1499	        if (req.body.sendEmail === true && !hasEmailed) {
1500	          await sendPricReqEmail(vendor_info, rfqItem_priceCode);
1501	        }
1502	      } else {
