1857	// Sourcing/admin flags a stale vendor quote for refresh. Sets requote_requested
1858	// on the RFQVendor (leaving quote_date untouched so the "Quoted <date>" tooltip
1859	// keeps showing the original date) and emails the factory to ask for a fresh price.
1860	Customer.requestRequote = async (req, result) => {
1861	  try {
1862	    const token = req.headers.authorization;
1863	    const userInfo = await getUserInfo(token);
1864	    const allowedRoles = ['admin', 'sourcing_manager', 'production'];
1865	    if (!userInfo || !allowedRoles.includes(userInfo.role)) {
1866	      return result(null, { status: 'forbidden' });
1867	    }
1868	
1869	    const rfqVendor = await sql.RFQVendor.findOne({ where: { RFQVendor_id: req.body.quote_id } });
1870	    if (!rfqVendor) {
1871	      return result(null, { status: 'quote_not_found' });
1872	    }
1873	
1874	    // Re-requesting a price reactivates the item for the vendor: auto-unarchive and
1875	    // clear the sticky opt-out so the 3-month cycle restarts once they answer.
1876	    await rfqVendor.update(
1877	      { requote_requested: true, RFQVendor_archived: false, RFQVendor_archive_optout: false },
1878	      { ref_id: rfqVendor.RFQitem_id_fk }
1879	    );
1880	
1881	    // Resolve the priceCode (style number) for the email — prefer the client-sent
1882	    // value, fall back to the RFQItem the quote belongs to.
1883	    let priceCode = req.body.priceCode;
1884	    if (!priceCode) {
1885	      const rfqItem = await sql.RFQItem.findOne({ where: { rfqItem_id: rfqVendor.RFQitem_id_fk } });
1886	      priceCode = rfqItem ? rfqItem.rfqItem_style_number : null;
1887	    }
1888	    // RFQVendor.vendor_id_fk stores Factory.id (see reqVendor), which is what
1889	    // emailVendorsForFactory expects.
1890	    if (priceCode && rfqVendor.vendor_id_fk) {
1891	      await emailVendorsForFactory(rfqVendor.vendor_id_fk, priceCode);
1892	    }
1893	
1894	    return result(null, { status: 'success' });
1895	  } catch (err) {
1896	    return result(null, { status: 'error', error: err });
1897	  }
1898	}
