1944	  let data = req.body.data
1945	  data = await utility.mapRFQItem(data)
1946	  const user = await getUserInfo(req.headers.authorization)
1947	
1948	  // For vendors, archive is PER-VENDOR — flip their own RFQVendor row, never the
1949	  // global RFQItem.rfqItem_archive flag (which would hide the item from Sourcing and
1950	  // other factories). 'archive' url means the click came from the archive view → restore.
1951	  if (user && user.role === 'vendor') {
1952	    let factoryId = user.factory_id
1953	    if (!factoryId && user.email) {
1954	      const v = await sql.vendor.findOne({ where: { vendor_email: user.email } })
1955	      if (v) factoryId = v.factory_id_fk
1956	    }
1957	    if (!factoryId) return result(null, [0])
1958	    const item = await sql.RFQItem.findOne({
1959	      where: { rfqItem_style_number: data.rfqItem_style_number },
1960	      attributes: ['rfqItem_id']
1961	    })
1962	    if (!item) return result(null, [0])
1963	    // url=='archive' → the click came from the archive view → restore (un-archive).
1964	    // A manual un-archive is sticky: set the opt-out so the lazy sweep won't re-archive
1965	    // it on the next list load. A manual archive clears the opt-out.
1966	    const unarchiving = req.body.url == 'archive'
1967	    return sql.RFQVendor.update(
1968	      {
1969	        RFQVendor_archived: unarchiving ? false : true,
1970	        RFQVendor_archive_optout: unarchiving ? true : false,
1971	      },
1972	      { where: { RFQitem_id_fk: item.rfqItem_id, vendor_id_fk: factoryId } }
1973	    )
1974	      .then(d => result(null, d))
1975	      .catch(err => result(err, null))
1976	  }
1977	
1978	  // Internal roles keep the global RFQItem archive behavior.
1979	  if (req.body.url == 'archive') {
1980	    data.rfqItem_archive = null
1981	  } else {
1982	    data.rfqItem_archive = 1
1983	  }
1984	  await sql.RFQItem.update(data, {
1985	    where: {
1986	      rfqItem_style_number: data.rfqItem_style_number
1987	    },
1988	    individualHooks: true
1989	  })
1990	    .then(async (data) => {
1991	      if (data) {
1992	        result(null, data);
1993	      }
1994	    })
1995	    .catch(err => {
1996	      result(err, null);
1997	    });
1998	}
