4402	/**
4403	 * Translate a Sequelize/upload error into a short bilingual reason string
4404	 * suitable for showing directly to a factory user.
4405	 *
4406	 * The full technical error is always logged server-side; this function only
4407	 * produces the human-readable portion that goes in the API response.
4408	 */
4409	function describeImportRowError(err, row) {
4410	  const name = err.name || '';
4411	  const msg  = (err.message || '').toLowerCase();
4412	
4413	  // ── Sequelize constraint / validation errors ───────────────────────────
4414	  if (name === 'SequelizeUniqueConstraintError') {
4415	    const field = err.errors?.[0]?.path || '';
4416	    return field
4417	      ? `Duplicate value in "${field}" · "${field}"字段值重复`
4418	      : 'Duplicate record · 记录重复';
4419	  }
4420	
4421	  if (name === 'SequelizeForeignKeyConstraintError') {
4422	    // All FK values in this import (customer, step, factory) are either
4423	    // system-provided or resolved before the DB call — a constraint error here
4424	    // is a system problem, not a factory data problem.
4425	    return 'System reference error — please contact support · 系统引用错误，请联系客服';
4426	  }
4427	
4428	  if (name === 'SequelizeValidationError') {
4429	    const fields = (err.errors || []).map(e => e.path).filter(Boolean);
4430	    if (fields.length) {
4431	      return `Invalid value in: ${fields.join(', ')} · 字段值无效：${fields.join('、')}`;
4432	    }
4433	    return 'Validation failed · 数据验证失败';
4434	  }
4435	
4436	  if (name === 'SequelizeDatabaseError') {
4437	    if (msg.includes('null value') || msg.includes('not-null')) {
4438	      // Extract column name from Postgres error if present
4439	      const colMatch = err.message.match(/column "([^"]+)"/);
4440	      const col = colMatch ? colMatch[1] : '';
4441	      return col
4442	        ? `Required field missing: ${col} · 必填字段为空：${col}`
4443	        : 'Required field is empty · 必填字段为空';
4444	    }
4445	    if (msg.includes('value too long') || msg.includes('character varying')) {
4446	      return 'A value is too long for its field · 某字段内容超出长度限制';
4447	    }
4448	    if (msg.includes('invalid input syntax')) {
4449	      const typeMatch = err.message.match(/type "([^"]+)"/);
4450	      const type = typeMatch ? typeMatch[1] : 'field';
4451	      return `Invalid format for ${type} (expected a number?) · ${type}格式无效（是否应为数字？）`;
4452	    }
4453	    return 'Database error · 数据库错误';
4454	  }
4455	
4456	  // ── Network / storage errors ───────────────────────────────────────────
4457	  if (msg.includes('econnrefused') || msg.includes('enotfound') || msg.includes('etimedout')) {
4458	    return 'Network error — please try again · 网络错误，请重试';
4459	  }
4460	
4461	  // ── Fallback: first 80 chars of the raw message, still bilingual label ─
4462	  const short = (err.message || 'unknown error').slice(0, 80);
4463	  return `${short} · 导入失败`;
4464	}
