4468	 *
4469	 * Parses a completed factory offer xlsx and creates:
4470	 *   1. One RFQGroup named by the factory (req.body.groupName)
4471	 *   2. One RFQItem per data row  (price code: foff-XXXX, step: @factories)
4472	 *   3. One RFQVendor quote record per item (linked to the uploading factory)
4473	 *   4. Images embedded in xlsx cells are uploaded to DigitalOcean Spaces
4474	 *
4475	 * Returns a summary: { created, items, errors, groupId, groupName }
4476	 */
4477	Customer.importFactoryRFQ = async (req, result) => {
4478	  const { getUserInfo } = require('../helpers/auth');
4479	  const { parseImport, getNextFoffPriceCodes } = require('../helpers/rfqBulkImport');
4480	  const { uploadBufferToSpaces } = require('../helpers/digitalocean');
4481	
4482	  try {
4483	    const token = req.headers.authorization;
4484	    const userInfo = await getUserInfo(token);
4485	    const factoryId = userInfo ? userInfo.factory_id : null;
4486	
4487	    const groupName = (req.body.groupName || '').trim() || 'Factory Upload';
4488	    if (!req.file || !req.file.buffer) {
4489	      return result(null, { created: 0, errors: ['No file received · 未收到文件'] });
4490	    }
4491	
4492	    // Parse the uploaded xlsx — catch format errors cleanly so they reach the
4493	    // user as a readable message instead of a 500.
4494	    let rows, images;
4495	    try {
4496	      ({ rows, images } = await parseImport(req.file.buffer));
4497	    } catch (parseErr) {
4498	      console.warn('importFactoryRFQ: parse error:', parseErr.message);
4499	      return result(null, {
4500	        created: 0,
4501	        errors: ['Invalid file format — please use the official template · 文件格式不正确，请使用官方模板'],
4502	      });
4503	    }
4504	
4505	    if (rows.length === 0) {
4506	      return result(null, { created: 0, errors: ['No data rows found · 未找到数据行，请至少填写一行'] });
4507	    }
4508	
4509	    // Build customer lookup map (name → id, case-insensitive)
4510	    const allCustomers = await sql.customers.findAll({
4511	      attributes: ['customers_id', 'customers_name'],
4512	      raw: true,
4513	    });
4514	    const customerMap = {};
4515	    allCustomers.forEach(c => {
4516	      if (c.customers_name) customerMap[c.customers_name.toLowerCase().trim()] = c.customers_id;
4517	    });
4518	
4519	    // Resolve @factories step ID
4520	    const factoriesStep = await sql.RFQStep.findOne({ where: { RFQStep_title: '@factories' } });
4521	    const stepId = factoriesStep ? factoriesStep.RFQStep_id : 3;
4522	
4523	    // Allocate price codes for all rows upfront (atomic sequence)
4524	    const priceCodes = await getNextFoffPriceCodes(sql, rows.length, Op);
4525	
4526	    // Create the RFQ Group
4527	    const group = await sql.RFQGroup.create({
4528	      RFQGroup_name: groupName,
4529	      IsLegacy: false,
4530	      user_id_fk: null,
4531	    });
4532	    const groupId = group.dataValues.RFQGroup_id;
4533	
4534	    const created = [];
4535	    const errors = [];
4536	
4537	    for (let i = 0; i < rows.length; i++) {
4538	      const row = rows[i];
4539	      try {
4540	        // Best-effort lookup — if the factory's dropdown value doesn't match
4541	        // (e.g. template was stale), we store null rather than failing the row.
