4552	          const imgKey = `images-${ts}-foff-offer.${ext}`;
4553	          try {
4554	            pictureFull = await uploadBufferToSpaces(imgBuf, imgKey, contentType);
4555	            pictureThumb = pictureFull; // same file; thumbnail resizing can be added later
4556	          } catch (imgUploadErr) {
4557	            console.warn(`importFactoryRFQ: image upload failed for row ${i + 1}:`, imgUploadErr.message);
4558	          }
4559	        }
4560	
4561	        // Create RFQItem
4562	        const item = await sql.RFQItem.create({
4563	          rfqItem_style_number:    priceCodes[i],
4564	          rfqItem_description:     row.description,
4565	          rfqItem_customer:        customerId,
4566	          rfqItem_quantity:        row.quantity != null ? String(row.quantity) : null,
4567	          rfqItem_case_pack:       row.case_pack != null ? String(row.case_pack) : null,
4568	          rfqItem_picture:         pictureFull,
4569	          rfqItem_picturethumb:    pictureThumb,
4570	          rfqItem_rfq_group:       groupId,
4571	          rfqItem_step:            stepId,
4572	          rfqItem_choosen_vendor:  factoryId,
4573	          rfqItem_divCode_id_fk:   FACTORY_IMPORT_DEFAULT_DIVISION,
4574	          rfqItem_active:          FACTORY_IMPORT_DEFAULT_STATUS_ID,
4575	          rfqItem_factories_step_at: new Date().toISOString(),
4576	          rfqItem_notes:           row.notes || null,
4577	        });
4578	        const itemId = item.dataValues.rfqItem_id;
4579	
4580	        // Calculate CBM/pc from carton dimensions
