3	/**
4	 * Classify a Sequelize / generic error into { isUser, message, code }.
5	 * code is used for system errors only (e.g. 'SYS-042').
6	 */
7	function classifyError(err, sysCode) {
8	  if (!err) return { isUser: false, message: 'Unknown error', code: sysCode };
9	
10	  const name = err.name || '';
11	
12	  // Sequelize user-facing errors
13	  if (name === 'SequelizeUniqueConstraintError') {
14	    const field = err.errors?.[0]?.path || 'field';
15	    return { isUser: true, message: `A record with that ${field} already exists. Please use a different value.` };
16	  }
17	  if (name === 'SequelizeValidationError') {
18	    const msg = err.errors?.map(e => e.message).join('; ') || err.message;
19	    return { isUser: true, message: `Validation failed: ${msg}` };
20	  }
21	  if (name === 'SequelizeForeignKeyConstraintError') {
22	    return { isUser: true, message: 'This record references another record that no longer exists. Please refresh and try again.' };
23	  }
24	  if (name === 'SequelizeEmptyResultError') {
25	    return { isUser: true, message: 'The requested record was not found.' };
26	  }
27	
28	  // System errors
29	  const message = err.message || String(err);
30	  return { isUser: false, message, code: sysCode };
31	}
32	
33	/**
34	 * Send a properly-formatted error response.
35	 * Uses res.status(400) for user errors, res.status(500) for system errors.
36	 */
37	function sendError(res, err, sysCode) {
38	  const { isUser, message, code } = classifyError(err, sysCode);
39	  console.error(`[${code || 'USER-ERR'}]`, err);
40	  if (isUser) {
41	    return res.status(400).json({ type: 'user', message });
42	  }
43	  return res.status(500).json({ type: 'system', message, code });
44	}
45	
46	module.exports = { classifyError, sendError };
