381	/**
382	 * Persist the Section 301 lookup to app_settings, then read it back and verify it
383	 * round-trips intact before the caller reports success.
384	 *
385	 * Why this exists: the upload handlers used to return the *parsed* summary right
386	 * after `AppSettingService.set(...)` without confirming the write actually landed.
387	 * So a save that silently failed, was rejected, or was truncated by the store still
388	 * reported "N codes loaded" to the admin — while `getSection301Status` then read back
389	 * nothing (or unparseable JSON) and every `lookupSection301` 404'd ("The requested
390	 * item was not found"). Verifying the round-trip turns a silent false-success into a
391	 * loud, specific error that names what actually happened.
392	 *
393	 * @param {object} lookup parsed `{ HTS: { list, rate, description } }` map
394	 * @returns {number} the verified code count read back from the store
395	 * @throws {Error} if the value is missing, unparseable, or short on read-back
396	 */
397	async function persistSection301Lookup(lookup) {
398	  const expected = Object.keys(lookup).length;
399	  await AppSettingService.set('section301_lookup', JSON.stringify(lookup));
400	
401	  const raw = await AppSettingService.get('section301_lookup');
402	  if (!raw) {
403	    throw new Error(
404	      `Section 301 save failed: parsed ${expected} codes but read back nothing. ` +
405	      `The app_settings store did not retain the value.`
406	    );
407	  }
408	  let stored;
409	  try {
410	    stored = JSON.parse(raw);
411	  } catch (e) {
412	    throw new Error(
413	      `Section 301 save failed: parsed ${expected} codes but the stored value did not ` +
414	      `parse back as JSON (read-back length ${raw.length}). It was likely truncated or ` +
415	      `corrupted in storage.`
416	    );
417	  }
418	  const got = Object.keys(stored).length;
419	  if (got !== expected) {
420	    throw new Error(
421	      `Section 301 save failed: parsed ${expected} codes but only ${got} read back. ` +
422	      `The app_settings store truncated or rejected part of the value.`
423	    );
424	  }
425	  return got;
426	}
