428	/**
429	 * POST /api/admin/section301/upload
430	 * Accepts a multipart PDF upload (field name: "pdf"), parses Section 301 tariff data,
431	 * stores the resulting lookup JSON in app_settings under the key "section301_lookup".
432	 *
433	 * Returns: { codesFound: number, lists: string[] }
434	 */
435	async function uploadSection301(req, res) {
436	  try {
437	    if (!req.file || !req.file.buffer) {
438	      return res.status(400).json({ error: 'No PDF file uploaded. Send as multipart field "pdf".' });
439	    }
440	    if (!req.file.mimetype.includes('pdf') && !req.file.originalname.toLowerCase().endsWith('.pdf')) {
441	      return res.status(400).json({ error: 'Uploaded file must be a PDF.' });
442	    }
443	
444	    // Parse PDF → lookup object
445	    const lookup = await parsePdf(req.file.buffer);
446	    const codesFound = Object.keys(lookup).length;
447	
448	    if (codesFound === 0) {
449	      return res.status(422).json({
450	        error: 'No HTS codes were found in the PDF. Check that this is a USTR Section 301 tariff list.',
451	      });
452	    }
453	
454	    // Store in app_settings, verifying the write round-trips before reporting success.
455	    const storedCount = await persistSection301Lookup(lookup);
456	
457	    // Summarise which lists were found
458	    const lists = [...new Set(Object.values(lookup).map(v => v.list))].sort();
459	
460	    res.json({ codesFound: storedCount, lists });
461	  } catch (err) {
462	    console.error('[section301/upload] error:', err.message);
463	    res.status(500).json({ error: err.message });
464	  }
465	}
466	
467	/**
468	 * POST /api/admin/section301/upload-csv
469	 * Preferred over the PDF uploader: takes a USTR Section 301 CSV (`HTS,Description,List`
470	 * columns; preamble and repeated headers tolerated). Parsing is column-addressed,
471	 * so codes are never silently mis-assigned to the wrong list the way the regex
472	 * PDF parser can be. List 4B rows are imported with rate 0 and labeled
473	 * "List 4B (suspended)" because that list was announced but never enacted.
474	 *
475	 * Multipart field name: "csv".
476	 *
477	 * Response:
478	 *   { codesFound, lists, skipped, conflicts, lineErrors }
479	 */
480	async function uploadSection301Csv(req, res) {
481	  try {
482	    if (!req.file || !req.file.buffer) {
483	      return res.status(400).json({ error: 'No CSV file uploaded. Send as multipart field "csv".' });
484	    }
485	    const lower = req.file.originalname.toLowerCase();
486	    const looksCsv = req.file.mimetype.includes('csv')
487	                  || req.file.mimetype.includes('text/plain')
488	                  || lower.endsWith('.csv');
489	    if (!looksCsv) {
490	      return res.status(400).json({ error: 'Uploaded file must be a .csv.' });
491	    }
492	
493	    const text = req.file.buffer.toString('utf8');
494	    const { lookup, summary } = parseSection301Csv(text);
495	
496	    if (summary.codesFound === 0) {
497	      return res.status(422).json({
498	        error: 'No HTS codes were found in the CSV. Check the file has "HTS,Description,List" columns.',
499	        summary,
500	      });
501	    }
502	
503	    // Verify the write actually round-trips before reporting success. A clean parse
504	    // summary alone does not prove the data persisted (see persistSection301Lookup).
505	    const storedCount = await persistSection301Lookup(lookup);
506	    res.json({ ...summary, storedCount });
507	  } catch (err) {
