788	    const { userId } = req.params;
789	    const { targetType } = req.body || {};
790	    if (!userId) return res.status(400).json({ error: 'userId is required' });
791	
792	    // Prevent impersonating while already impersonating
793	    const callerInfo = await getUserInfo(req.headers.authorization);
