796	    }
797	
798	    const privateKey = process.env.JWT_PRIVATE_KEY;
799	    let tokenData;
800	
801	    if (targetType === 'vendor') {
802	      const vendor = await sql.vendor.findOne({
803	        where: { vendor_id: userId },
804	        attributes: [
805	          'vendor_id',
806	          'vendor_name',
807	          'vendor_lastname',
808	          'vendor_email',
809	          'vendor_access',
810	          'vendor_company_nickname',
811	          'factory_id_fk',
812	        ],
813	      });
814	      if (!vendor) return res.status(404).json({ error: 'Vendor not found' });
815	
816	      tokenData = {
817	        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
818	          || vendor.vendor_company_nickname
819	          || vendor.vendor_email
820	          || `Vendor ${vendor.vendor_id}`,
821	        user_id: vendor.vendor_id,
822	        email: vendor.vendor_email,
823	        role: 'vendor',
824	        access: vendor.vendor_access,
825	        factory_id: vendor.factory_id_fk,
826	        impersonated_by: callerInfo.user_id,
827	      };
828	    } else if (targetType === 'factory') {
829	      const factory = await sql.Factory.findOne({
830	        where: { id: userId },
831	        attributes: ['id', 'factory_name', 'factory_nickname', 'factory_access'],
832	      });
833	      if (!factory) return res.status(404).json({ error: 'Factory not found' });
834	
835	      const vendor = await sql.vendor.findOne({
836	        where: { factory_id_fk: userId },
837	        attributes: [
838	          'vendor_id',
839	          'vendor_name',
840	          'vendor_lastname',
841	          'vendor_email',
842	          'vendor_access',
843	          'vendor_company_nickname',
844	          'factory_id_fk',
845	        ],
846	        order: [
847	          ['vendor_access', 'ASC'],
848	          ['vendor_id', 'ASC'],
849	        ],
850	      });
851	
852	      tokenData = vendor ? {
853	        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
854	          || vendor.vendor_company_nickname
855	          || vendor.vendor_email
856	          || factory.factory_nickname
857	          || factory.factory_name
858	          || `Factory ${factory.id}`,
859	        user_id: vendor.vendor_id,
860	        email: vendor.vendor_email,
861	        role: 'vendor',
862	        access: vendor.vendor_access || factory.factory_access,
863	        factory_id: factory.id,
864	        impersonated_by: callerInfo.user_id,
865	      } : {
866	        name: factory.factory_nickname || factory.factory_name || `Factory ${factory.id}`,
867	        user_id: factory.id,
868	        email: null,
869	        role: 'vendor',
870	        access: factory.factory_access,
871	        factory_id: factory.id,
872	        impersonated_by: callerInfo.user_id,
873	      };
874	    } else {
875	      const targetUser = await sql.users.findOne({
876	        where: { id: userId },
877	        attributes: ['id', 'name', 'lastname', 'email', 'level'],
878	      });
879	      if (!targetUser) return res.status(404).json({ error: 'User not found' });
880	
881	      tokenData = {
882	        name: `${targetUser.name || ''} ${targetUser.lastname || ''}`.trim(),
883	        user_id: targetUser.id,
884	        email: targetUser.email,
885	        role: targetUser.level,
886	        impersonated_by: callerInfo.user_id,
887	      };
888	
889	      if (targetUser.level === 'vendor') {
890	        const vendor = await sql.vendor.findOne({
891	          where: { vendor_email: targetUser.email },
892	          attributes: ['vendor_access', 'factory_id_fk'],
893	        });
894	        if (vendor) {
895	          tokenData.access = vendor.vendor_access;
896	          tokenData.factory_id = vendor.factory_id_fk;
897	        }
898	      }
899	    }
900	
901	    const token = jwt.sign(tokenData, privateKey, {
902	      algorithm: 'RS256',
903	      expiresIn: '2h',
904	    });
905	
906	    res.json({ token });
907	  } catch (err) {
908	    console.error('[admin/impersonate] error:', err.message);
909	    res.status(500).json({ error: 'Impersonation failed' });
910	  }
911	}
