32	/**
33	 * Providers that support the cache_control content-block format via OpenRouter.
34	 * OpenAI is excluded — it caches automatically with no markers needed.
35	 */
36	const CACHE_CONTROL_PROVIDERS = ['anthropic/', 'deepseek/', 'google/'];
37	
38	/**
39	 * Add cache_control breakpoints for providers that support the content-block
40	 * caching format via OpenRouter:
41	 *   - anthropic/*  — ephemeral cache, 5-min TTL
42	 *   - deepseek/*   — same cache_control syntax as Anthropic
43	 *   - google/*     — implicit context caching via OpenRouter
44	 *
45	 * Two breakpoints per turn:
46	 *   1. system message  → caches the static ~3,600-token system prompt after turn 1
47	 *   2. last assistant  → caches the growing conversation history each turn
48	 *
49	 * OpenAI is left unchanged — it caches repeated prefixes automatically.
50	 * Other providers ignore unknown content-block fields.
51	 *
52	 * @param {string} model     OpenRouter model ID (e.g. "anthropic/claude-sonnet-4-5")
53	 * @param {Array}  messages  [{role, content: string}]
54	 * @returns {Array} new array with cache_control injected where appropriate
55	 */
56	function _applyCachingMarkers(model, messages) {
57	  const needsMarkers = CACHE_CONTROL_PROVIDERS.some(p => model.startsWith(p));
58	  if (!needsMarkers) return messages;
59	
60	  const result = messages.map(msg => ({ ...msg }));
61	
62	  // Cache the system prompt (always the same ~3,600 token block)
63	  const systemIdx = result.findIndex(m => m.role === 'system');
64	  if (systemIdx !== -1 && typeof result[systemIdx].content === 'string') {
65	    result[systemIdx] = {
66	      ...result[systemIdx],
67	      content: [{ type: 'text', text: result[systemIdx].content, cache_control: { type: 'ephemeral' } }],
68	    };
69	  }
70	
71	  // Cache the last assistant message to freeze accumulated conversation history.
72	  // On each subsequent turn only the new user message is uncached.
73	  let lastAssistantIdx = -1;
74	  for (let i = result.length - 1; i >= 0; i--) {
75	    if (result[i].role === 'assistant') { lastAssistantIdx = i; break; }
76	  }
77	  if (lastAssistantIdx !== -1 && typeof result[lastAssistantIdx].content === 'string') {
78	    result[lastAssistantIdx] = {
79	      ...result[lastAssistantIdx],
80	      content: [{ type: 'text', text: result[lastAssistantIdx].content, cache_control: { type: 'ephemeral' } }],
81	    };
82	  }
83	
84	  return result;
85	}
86	
87	exports._applyCachingMarkers = _applyCachingMarkers;
