97	  const body = { model, messages: cachedMessages, max_tokens, temperature };
98	  if (reasoning) body.reasoning = reasoning;
99	  const res = await axios.post(
100	    `${BASE}/chat/completions`,
101	    body,
102	    { headers: headers(), timeout: 90000 }
103	  );
104	  return res.data;
105	};
