82	 * DeepSeek includes prompt_cache_hit_tokens and prompt_cache_miss_tokens on
83	 * every response. A hit rate below 80% for multi-turn sessions indicates the
84	 * prefix is changing between requests (check for dynamic content at the start
85	 * of the messages array).
86	 */
87	function _logCacheMetrics(model, usage) {
88	  if (!usage) return;
89	  const hit  = usage.prompt_cache_hit_tokens  ?? 0;
90	  const miss = usage.prompt_cache_miss_tokens ?? 0;
91	  const comp = usage.completion_tokens        ?? 0;
92	  const total = hit + miss;
93	  const hitPct = total > 0 ? Math.round((hit / total) * 100) : 0;
94	  console.log(
95	    `[deepseek] model=${model} ` +
96	    `cache_hit=${hit} cache_miss=${miss} completion=${comp} ` +
97	    `hit_rate=${hitPct}%${hit === 0 && miss > 0 ? ' (cold — first request or prefix changed)' : ''}`
98	  );
99	}
