1	'use strict';
2	const jwksClient = require('jwks-rsa');
3	const jwt = require('jsonwebtoken');
4	const bcrypt = require('bcrypt');
5	const crypto = require('crypto');
6	const sql = require('../models/db');
7	
8	const TENANT_ID = process.env.AZURE_TENANT_ID;
9	const CLIENT_ID = process.env.AZURE_CLIENT_ID;
10	
11	// Lazy-init so tests can inject env before the module loads
12	let _jwks = null;
13	function getJwksClient() {
14	  if (!_jwks) {
15	    _jwks = jwksClient({
16	      jwksUri: `https://login.microsoftonline.com/${TENANT_ID}/discovery/v2.0/keys`,
17	      cache: true,
18	      cacheMaxEntries: 5,
19	      cacheMaxAge: 10 * 60 * 1000, // 10 min
20	    });
21	  }
22	  return _jwks;
23	}
24	
25	function _getSigningKey(kid) {
26	  return new Promise((resolve, reject) => {
27	    getJwksClient().getSigningKey(kid, (err, key) => {
28	      if (err) return reject(err);
29	      resolve(key.getPublicKey());
30	    });
31	  });
32	}
33	
34	/**
35	 * Validate an Azure AD ID token.
36	 * Returns the decoded payload on success; throws on failure.
37	 */
38	async function verifyAzureToken(idToken) {
39	  const decoded = jwt.decode(idToken, { complete: true });
40	  if (!decoded) throw new Error('Invalid token format');
41	
42	  const signingKey = await _getSigningKey(decoded.header.kid);
43	
44	  const payload = jwt.verify(idToken, signingKey, {
45	    algorithms: ['RS256'],
46	    audience: CLIENT_ID,
47	    issuer: `https://login.microsoftonline.com/${TENANT_ID}/v2.0`,
48	  });
49	  return payload;
50	}
51	
52	/**
53	 * Look up an existing user by email, or auto-create one from Azure claims.
54	 * Returns a plain object with at least: id, name, lastname, email, level, userType.
55	 */
56	async function findOrCreateUser(azurePayload) {
57	  const email = (
58	    azurePayload.preferred_username ||
59	    azurePayload.email ||
60	    ''
61	  ).toLowerCase().trim();
62	
63	  if (!email) throw new Error('No email found in Azure token claims');
64	
65	  // 1 — Check internal users table
66	  const user = await sql.users.findOne({ where: { email } });
67	  if (user) return { ...user.dataValues, userType: 'user' };
68	
69	  // 2 — Check vendor table
70	  const vendor = await sql.vendor.findOne({ where: { vendor_email: email } });
71	  if (vendor) {
72	    return {
73	      id: vendor.vendor_id,
74	      email: vendor.vendor_email,
75	      level: 'vendor',
76	      name: vendor.vendor_name,
77	      lastname: vendor.vendor_lastname,
78	      factory_id: vendor.factory_id_fk,
79	      userType: 'vendor',
80	    };
81	  }
82	
83	  // 3 — Auto-provision: create a new internal user from Azure profile
84	  const nameParts = (azurePayload.name || email.split('@')[0]).split(' ');
85	  const firstName = azurePayload.given_name  || nameParts[0]                      || '';
86	  const lastName  = azurePayload.family_name || nameParts.slice(1).join(' ')      || '';
87	  const randomPass = await bcrypt.hash(crypto.randomUUID(), 12);
88	  const today = new Date().toISOString().split('T')[0];
89	
90	  const newUser = await sql.users.create({
91	    name:     firstName,
92	    lastname: lastName,
93	    email,
94	    level:    'designer',   // default — admin can promote via User Management
95	    passw:    randomPass,
96	    status:   'active',
97	    adddate:  today,
98	  });
99	
100	  return { ...newUser.dataValues, userType: 'user' };
101	}
102	
103	module.exports = { verifyAzureToken, findOrCreateUser };
