224	/**
225	 * Parse an uploaded factory offer xlsx file.
226	 *
227	 * Returns:
228	 *   rows  — array of data objects, one per non-empty data row
229	 *   images — map of worksheet row number (1-indexed) → { buffer, extension }
230	 *
231	 * @param {Buffer} buffer
232	 * @returns {Promise<{ rows: Array, images: Object }>}
233	 */
234	exports.parseImport = async (buffer) => {
235	  const workbook = new ExcelJS.Workbook();
236	  await workbook.xlsx.load(buffer);
237	
238	  // Use the first non-hidden, non-lookup worksheet
239	  let ws = workbook.worksheets.find(s =>
240	    s.state !== 'hidden' && s.name.toLowerCase() !== 'lookups' && s.name.toLowerCase() !== 'instructions'
241	  );
242	  if (!ws) ws = workbook.worksheets[0];
243	  if (!ws) throw new Error('No worksheet found · 文件中未找到工作表');
244	
245	  // ── Locate the header row (the row whose first cell is "Description") ──
246	  let headerRowNum = null;
247	  ws.eachRow((row, rowNumber) => {
248	    if (headerRowNum) return;
249	    const first = String(row.getCell(1).value || '').trim();
250	    if (first.toLowerCase() === 'description') headerRowNum = rowNumber;
251	  });
252	
253	  if (!headerRowNum) {
254	    throw new Error('Header row not found · 未找到标题行，请使用官方模板');
255	  }
256	
257	  // ── Build column index map from header labels ─────────────────────────
258	  const colMap = {};
259	  ws.getRow(headerRowNum).eachCell((cell, colNumber) => {
260	    const val = String(cell.value || '').toLowerCase();
261	    if (val.includes('description'))      colMap.description    = colNumber;
262	    else if (val.includes('customer'))    colMap.customer       = colNumber;
263	    else if (val.includes('quantity'))    colMap.quantity       = colNumber;
264	    else if (val.includes('case pack'))   colMap.case_pack      = colNumber;
265	    else if (val.includes('quote price')) colMap.quote_price    = colNumber;
266	    else if (val.includes('price terms')) colMap.price_terms    = colNumber;
267	    else if (val.includes('carton length')) colMap.carton_length = colNumber;
268	    else if (val.includes('carton width'))  colMap.carton_width  = colNumber;
269	    else if (val.includes('carton height')) colMap.carton_height = colNumber;
270	    else if (val.includes('lead time'))   colMap.lead_time      = colNumber;
271	    else if (val.includes('fob country')) colMap.fob_country    = colNumber;
272	    else if (val.includes('fob port'))    colMap.fob_port       = colNumber;
273	    else if (val.includes('notes'))       colMap.notes          = colNumber;
274	  });
275	
276	  const dataStart = headerRowNum + 1;
277	
278	  // ── Extract data rows ─────────────────────────────────────────────────
279	  const rows = [];
280	  ws.eachRow((row, rowNumber) => {
281	    if (rowNumber < dataStart) return;
282	
283	    const descCell = row.getCell(colMap.description || 1);
284	    const desc = String(descCell.value || '').trim();
285	    if (!desc) return; // skip empty rows
286	
287	    const getStr = (col) => String(row.getCell(col || 1).value || '').trim();
288	    const getNum = (col) => {
289	      const v = row.getCell(col || 1).value;
290	      if (v === null || v === undefined || v === '') return null;
291	      const n = parseFloat(String(v));
292	      return isNaN(n) ? null : n;
293	    };
294	
295	    rows.push({
296	      description:   desc,
297	      customer:      getStr(colMap.customer),
298	      quantity:      getNum(colMap.quantity),
299	      case_pack:     getNum(colMap.case_pack),
300	      quote_price:   getNum(colMap.quote_price),
301	      price_terms:   getStr(colMap.price_terms) || 'FOB',
302	      carton_length: getNum(colMap.carton_length),
303	      carton_width:  getNum(colMap.carton_width),
304	      carton_height: getNum(colMap.carton_height),
305	      lead_time:     getNum(colMap.lead_time),
306	      fob_country:   getStr(colMap.fob_country),
307	      fob_port:      getStr(colMap.fob_port),
308	      notes:         getStr(colMap.notes),
309	      _rowNumber:    rowNumber,
310	    });
311	  });
312	
313	  // ── Extract embedded images ───────────────────────────────────────────
314	  // ExcelJS exposes workbook.getImages() which returns [{imageId, range: {tl:{col,row},...}}]
315	  // range.tl.row is 0-indexed (row 1 of the sheet = index 0)
316	  const images = {};
317	  try {
318	    const embeddedImages = workbook.getImages();
319	    for (const img of embeddedImages) {
320	      // Convert 0-indexed ExcelJS row to 1-indexed worksheet row number
321	      const worksheetRowNum = Math.floor(img.range.tl.row) + 1;
322	      const imageData = workbook.getImage(img.imageId);
323	      if (imageData && imageData.buffer && worksheetRowNum >= dataStart) {
324	        // Only keep the first image per row
325	        if (!images[worksheetRowNum]) {
326	          images[worksheetRowNum] = {
327	            buffer: Buffer.isBuffer(imageData.buffer)
328	              ? imageData.buffer
329	              : Buffer.from(imageData.buffer),
330	            extension: imageData.extension || 'jpeg',
331	          };
332	        }
333	      }
334	    }
335	  } catch (imgErr) {
336	    // Image extraction is best-effort; don't fail the whole import
337	    console.warn('rfqBulkImport: image extraction error (non-fatal):', imgErr.message);
338	  }
339	
340	  return { rows, images };
341	};
