343	/**
344	 * Allocate the next `count` sequential foff-XXXX price codes globally.
345	 *
346	 * @param {object} sql - Sequelize model namespace
347	 * @param {number} count
348	 * @param {object} Op - Sequelize Op
349	 * @returns {Promise<string[]>}
350	 */
351	exports.getNextFoffPriceCodes = async (sql, count, Op) => {
352	  const existing = await sql.RFQItem.findAll({
353	    where: { rfqItem_style_number: { [Op.like]: 'foff-%' } },
354	    attributes: ['rfqItem_style_number'],
355	    raw: true,
356	  });
357	
358	  let maxNum = 0;
359	  for (const item of existing) {
360	    const match = String(item.rfqItem_style_number || '').match(/^foff-(\d+)$/);
361	    if (match) {
362	      const n = parseInt(match[1], 10);
363	      if (n > maxNum) maxNum = n;
364	    }
365	  }
366	
367	  return Array.from({ length: count }, (_, i) => {
368	    const num = maxNum + i + 1;
369	    return `foff-${String(num).padStart(4, '0')}`;
370	  });
371	};
