1	// Extract @handles from comment text. Supports @FirstName and @FirstName.LastName.
2	function parseMentions(text) {
3	  if (!text || typeof text !== 'string') return [];
4	  const matches = text.match(/@([A-Za-z][A-Za-z0-9._-]*)/g) || [];
5	  return [...new Set(matches.map(m => m.slice(1).toLowerCase()))];
6	}
7	
8	// Resolve parsed handles to user IDs by matching against name / name.lastname.
9	function resolveMentions(handles, users) {
10	  if (!handles.length || !users.length) return [];
11	  const matchedIds = new Set();
12	  for (const handle of handles) {
13	    for (const user of users) {
14	      const first = (user.name || '').toLowerCase();
15	      const full = `${user.name || ''}.${user.lastname || ''}`.toLowerCase();
16	      if (handle === first || handle === full) matchedIds.add(user.id);
17	    }
18	  }
19	  return [...matchedIds];
20	}
21	
22	module.exports = { parseMentions, resolveMentions };
