1	/**
2	 * Factory metadata accessors used by the editor/admin surfaces and by the
3	 * sub-grid FOB-country auto-fill.
4	 *
5	 * Two reads, one write:
6	 *   - listAll()                 → [{ id, factory_name, factory_nickname, factory_country, factory_status }]
7	 *   - countryMapByNickname()    → { [factory_nickname]: factory_country }   (used by clients to look up
8	 *                                                                            country without hitting the API per row)
9	 *   - updateCountry(id, value)  → number of rows updated (0 or 1)
10	 *
11	 * Kept as a thin module rather than a Sequelize-class method so the unit
12	 * tests can inject a fake `sql` without booting the whole models tree.
13	 */
14	
15	'use strict';
16	
17	const sql = require('../models/db');
18	
19	/**
20	 * Return every factory in a list. Order by sort_order so the admin UI matches
21	 * the order users already see elsewhere in the app.
22	 */
23	async function listAll() {
24	  const rows = await sql.Factory.findAll({
25	    attributes: ['id', 'factory_name', 'factory_nickname', 'factory_country', 'factory_status'],
26	    order: [['sort_order', 'ASC'], ['id', 'ASC']],
27	  });
28	  // .get({ plain: true }) strips Sequelize internals so this is a plain JSON payload.
29	  return rows.map(r => (typeof r.get === 'function' ? r.get({ plain: true }) : r));
30	}
31	
32	/**
33	 * Build a compact lookup object keyed by factory_nickname.
34	 *
35	 * Two nicknames pointing at the same country is fine — we just store the last
36	 * one we see. Factories without a nickname OR without a country are omitted
37	 * (an entry with no country would just bloat the response).
38	 */
39	async function countryMapByNickname() {
40	  const rows = await sql.Factory.findAll({
41	    attributes: ['factory_nickname', 'factory_country'],
42	    where: {
43	      factory_nickname: { [sql.Sequelize?.Op?.ne ?? '$ne']: null },
44	    },
45	  }).catch(async () => {
46	    // Some test stubs don't expose Sequelize.Op — fall back to a plain findAll
47	    // and filter in memory.
48	    return sql.Factory.findAll({ attributes: ['factory_nickname', 'factory_country'] });
49	  });
50	
51	  const out = {};
52	  for (const r of rows) {
53	    const plain = typeof r.get === 'function' ? r.get({ plain: true }) : r;
54	    const nick    = (plain.factory_nickname || '').trim();
55	    const country = (plain.factory_country  || '').trim();
56	    if (!nick || !country) continue;
57	    out[nick] = country;
58	  }
59	  return out;
60	}
61	
62	/**
63	 * Update a single factory's country. Returns the number of rows affected.
64	 * Throws if id isn't a positive integer.
65	 */
66	async function updateCountry(id, country) {
67	  const numericId = parseInt(id, 10);
68	  if (!Number.isInteger(numericId) || numericId <= 0) {
69	    throw new Error('factory id must be a positive integer');
70	  }
71	  // Allow clearing the field with an empty string → store null.
72	  const value = country && country.trim() ? country.trim() : null;
73	  const [affected] = await sql.Factory.update(
74	    { factory_country: value },
75	    { where: { id: numericId } },
76	  );
77	  return affected;
78	}
79	
80	module.exports = { listAll, countryMapByNickname, updateCountry };
