1	/**
2	 * MFN base tariff rate lookup against the bundled USITC HTS revision.
3	 *
4	 * Data source: data/hts-rates.json (generated by scripts/fetch-hts-rates.js
5	 * from https://hts.usitc.gov/reststop/exportList). Each entry is
6	 *   { d: <description, ≤120 chars>, g: <general rate text from column 1> }
7	 *
8	 * Lookup strategy at runtime is O(1) with a 3-step fallback:
9	 *   1. Exact match on the supplied code (normalized to USITC's dotted form)
10	 *   2. 8-digit prefix match (NNNN.NN.NN.**) — covers the common case where the
11	 *      AI returns a 10-digit code and only the 8-digit parent carries the rate
12	 *   3. 6-digit prefix match (NNNN.NN.**) — last-ditch fallback to the heading
13	 *
14	 * The `general` column from USITC is stored verbatim because rates take many
15	 * forms: "Free", "5.3%", "13.5¢/kg + 4.4%", "0.7¢ each + 4.5%". parseGeneralRate()
16	 * normalizes the common ad valorem cases to a decimal percent; mixed-unit rates
17	 * cannot be reduced to a single number and return null.
18	 */
19	
20	'use strict';
21	
22	const fs   = require('fs');
23	const path = require('path');
24	
25	const DATA_PATH = path.join(__dirname, '..', 'data', 'hts-rates.json');
26	
27	let _lookup = null;
28	let _byPrefix = null;
29	
30	function loadLookup() {
31	  if (_lookup) return _lookup;
32	  try {
33	    _lookup = JSON.parse(fs.readFileSync(DATA_PATH, 'utf8'));
34	  } catch (e) {
35	    _lookup = {};
36	  }
37	  _byPrefix = null;
38	  return _lookup;
39	}
40	
41	/** Allow tests to inject a fixture in place of the bundled file. */
42	function _setLookupForTests(obj) {
43	  _lookup   = obj || {};
44	  _byPrefix = null;
45	}
46	
47	/**
48	 * Normalize an HTS code to USITC's dotted form.
49	 *   "39264000"        → "3926.40.00"
50	 *   "3926.40.0010"    → "3926.40.00.10"
51	 *   "3926.40.00.10"   → "3926.40.00.10"
52	 *   "3926.40.00"      → "3926.40.00"
53	 *
54	 * Returns the input verbatim (trimmed) when it cannot be normalized.
55	 */
56	function normalizeHtsCode(code) {
57	  if (!code || typeof code !== 'string') return '';
58	  const digits = code.replace(/\D/g, '');
59	  if (digits.length === 4) return digits.slice(0, 4);
60	  if (digits.length === 6) return `${digits.slice(0, 4)}.${digits.slice(4, 6)}`;
61	  if (digits.length === 8) return `${digits.slice(0, 4)}.${digits.slice(4, 6)}.${digits.slice(6, 8)}`;
62	  if (digits.length === 10) return `${digits.slice(0, 4)}.${digits.slice(4, 6)}.${digits.slice(6, 8)}.${digits.slice(8, 10)}`;
63	  return code.trim();
64	}
65	
66	/**
67	 * Parse a USITC `general` rate string into a decimal percent.
68	 *   "Free"      → 0
69	 *   "5.3%"      → 5.3
70	 *   "  9.3% "   → 9.3
71	 *   "13.5¢/kg + 4.4%" → null  (mixed unit — cannot reduce to a single percent)
72	 *   "0.7¢/kg"   → null
73	 *   ""/null/undef → null
74	 */
75	function parseGeneralRate(text) {
76	  if (text == null) return null;
77	  const s = String(text).trim();
78	  if (!s) return null;
79	  if (/^free$/i.test(s)) return 0;
80	
81	  // Mixed compound rates (specific + ad valorem). We can't reduce these
82	  // without unit price + weight, so fall back to null.
83	  if (/[¢$]/.test(s)) return null;
84	
85	  // Pure ad valorem percent — accept the first percent value in the string
86	  const m = s.match(/(\d+(?:\.\d+)?)\s*%/);
87	  if (m) return parseFloat(m[1]);
88	
89	  return null;
90	}
91	
92	/**
93	 * Build (and cache) the 8/6/4-digit prefix indices for fallback lookups.
94	 *
95	 * `eight` and `six` point at a single representative code per prefix — first
96	 * one wins. `four` is a list of representative codes per heading, used so the
97	 * 4-digit fallback can detect when subheadings disagree on rate and refuse
98	 * to guess (e.g. heading 8543 has children with 0%, 2.6%, and 4% — picking
99	 * one would be wrong).
100	 */
101	function buildPrefixIndex() {
102	  if (_byPrefix) return _byPrefix;
103	  const lookup = loadLookup();
104	  const eight = new Map();
105	  const six   = new Map();
106	  const four  = new Map();  // 'NNNN' → array of representative codes (one per distinct sub-prefix)
107	  const seenSix = new Set();
108	  for (const code of Object.keys(lookup)) {
109	    const norm = normalizeHtsCode(code);
110	    const digits = norm.replace(/\D/g, '');
111	    if (digits.length >= 8) {
112	      const k8 = norm.split('.').slice(0, 3).join('.');  // NNNN.NN.NN
113	      if (!eight.has(k8)) eight.set(k8, code);
114	    }
115	    if (digits.length >= 6) {
116	      const k6 = norm.split('.').slice(0, 2).join('.');  // NNNN.NN
117	      if (!six.has(k6)) six.set(k6, code);
118	      if (!seenSix.has(k6)) {
119	        seenSix.add(k6);
120	        const k4 = k6.slice(0, 4);
121	        if (!four.has(k4)) four.set(k4, []);
122	        four.get(k4).push(code);
123	      }
124	    }
125	  }
126	  _byPrefix = { eight, six, four };
127	  return _byPrefix;
128	}
129	
130	/**
131	 * Look up a single HTS code and return the resolved rate.
132	 *
133	 * Fallback chain: exact → 8-digit prefix → 6-digit prefix → 4-digit heading.
134	 * The 4-digit step exists because the AI sometimes returns invalid heading
135	 * codes like `4414.00.0000` (no such subheading; `4414` only has `.10` and
136	 * `.90`). When ALL subheadings under the heading share a rate, that rate is
137	 * unambiguous and we return it. When they disagree, we return found:true
138	 * but rate:null so the UI can prompt the user to enter the rate manually.
139	 *
140	 * @param {string} htsCode  HTS code (8 or 10 digits, dotted or undotted)
141	 * @returns {{
142	 *   found:        boolean,
143	 *   hts:          string|null,        // the code that actually hit
144	 *   rate:         number|null,        // parsed decimal percent, or null if non-ad-valorem or ambiguous
145	 *   rateText:     string|null,        // raw USITC `general` column text
146	 *   description:  string|null,
147	 *   matchType:    'exact'|'prefix8'|'prefix6'|'prefix4'|'prefix4-ambiguous'|null,
148	 * }}
149	 */
150	function lookupRate(htsCode) {
151	  const lookup = loadLookup();
152	  const empty  = { found: false, hts: null, rate: null, rateText: null, description: null, matchType: null };
153	  if (!htsCode) return empty;
154	
155	  const norm = normalizeHtsCode(htsCode);
156	
157	  // 1. Exact match
158	  if (lookup[norm]) {
159	    const e = lookup[norm];
160	    return { found: true, hts: norm, rate: parseGeneralRate(e.g), rateText: e.g, description: e.d, matchType: 'exact' };
161	  }
162	
163	  const { eight, six, four } = buildPrefixIndex();
164	
165	  // 2. 8-digit prefix
166	  const k8 = norm.split('.').slice(0, 3).join('.');
167	  if (eight.has(k8)) {
168	    const hit = eight.get(k8);
169	    const e = lookup[hit];
170	    return { found: true, hts: hit, rate: parseGeneralRate(e.g), rateText: e.g, description: e.d, matchType: 'prefix8' };
171	  }
172	
173	  // 3. 6-digit prefix
174	  const k6 = norm.split('.').slice(0, 2).join('.');
175	  if (six.has(k6)) {
176	    const hit = six.get(k6);
177	    const e = lookup[hit];
178	    return { found: true, hts: hit, rate: parseGeneralRate(e.g), rateText: e.g, description: e.d, matchType: 'prefix6' };
179	  }
180	
181	  // 4. 4-digit heading. Collect candidate rates from every distinct subheading
182	  // under this heading; only return a rate when they all agree (the heading is
183	  // unambiguous at the ad valorem level).
184	  const k4 = norm.slice(0, 4);
185	  if (four.has(k4)) {
186	    const candidates = four.get(k4).map(c => ({ code: c, entry: lookup[c], rate: parseGeneralRate(lookup[c].g) }));
187	    const rates = new Set(candidates.map(c => (c.rate == null ? '__null__' : c.rate)));
188	    if (rates.size === 1 && !rates.has('__null__')) {
189	      const pick = candidates[0];
190	      return {
191	        found: true,
192	        hts: pick.code,
193	        rate: pick.rate,
194	        rateText: pick.entry.g,
195	        description: `Heading ${k4} (all subheadings) — ${pick.entry.d}`,
196	        matchType: 'prefix4',
197	      };
198	    }
199	    // Subheadings disagree (or include non-ad-valorem). Don't guess.
200	    return {
201	      found: true,
202	      hts: k4,
203	      rate: null,
