1	/**
2	 * Section 301 tariff data extraction.
3	 *
4	 * Parses the USTR Section 301 tariff PDF and builds an O(1) lookup object:
5	 *   { "NNNN.NN.NNNN": { list: "List 3", rate: 25, description: "..." } }
6	 *
7	 * Strategy (no AI needed — deterministic):
8	 *   1. Extract text from the PDF with pdf-parse
9	 *   2. Detect section boundaries (List 1/2/3/4A) by scanning for marker phrases
10	 *   3. Within each section, scan for HTS code patterns (NNNN.NN.NNNN)
11	 *   4. Capture up to 120 chars of surrounding context as the description
12	 *   5. Associate each code with the detected list + known rate
13	 *
14	 * HTS code matching at lookup time (O(1)):
15	 *   Exact match on 10-digit code first, then fall back to 8-digit prefix
16	 *   (e.g. "8471.30.01" matches "8471.30.0100").
17	 */
18	
19	'use strict';
20	
21	// Lazy-require pdf-parse so that a missing or broken native dependency in the
22	// deployment environment does not crash the server on startup.
23	// The require is deferred until parsePdf() is actually called.
24	let _pdfParse;
25	function getPdfParse() {
26	  if (!_pdfParse) { _pdfParse = require('pdf-parse'); }
27	  return _pdfParse;
28	}
29	
30	/** Rates are known per list — no need to parse them from the PDF. */
31	const LIST_RATES = {
32	  'List 1':  25,
33	  'List 2':  25,
34	  'List 3':  25,
35	  'List 4A': 7.5,
36	};
37	
38	/**
39	 * Parse a Section 301 PDF buffer and return the lookup object.
40	 * @param {Buffer} buffer  Raw PDF bytes (e.g. from multer memoryStorage)
41	 * @returns {Promise<Record<string, {list:string, rate:number, description:string}>>}
42	 */
43	async function parsePdf(buffer) {
44	  const pdfParse = getPdfParse();
45	  const data = await pdfParse(buffer);
46	  return parseText(data.text);
47	}
48	
49	/**
50	 * Parse pre-extracted PDF text into the Section 301 lookup.
51	 * Exported so it can be unit-tested without a real PDF.
52	 * @param {string} text
53	 * @returns {Record<string, {list:string, rate:number, description:string}>}
54	 */
55	function parseText(text) {
56	  // Normalise line endings and collapse excessive whitespace
57	  const clean = text.replace(/\r\n/g, '\n').replace(/[ \t]{2,}/g, ' ');
58	
59	  const sections = detectSections(clean);
60	  const lookup = {};
61	
62	  // HTS code pattern — 4 digits, dot, 2 digits, dot, 2–4 digits (may or may not be 10-digit)
63	  // word boundaries prevent matching things like 1234.56.7890xyz
64	  const HTS_RE = /\b(\d{4}\.\d{2}\.(?:\d{4}|\d{2}))\b/g;
65	
66	  for (const section of sections) {
67	    HTS_RE.lastIndex = 0;
68	    let m;
69	    while ((m = HTS_RE.exec(section.text)) !== null) {
70	      const raw = m[1];
71	      const code = normalizeHtsCode(raw);
72	
73	      if (lookup[code]) continue; // first section win (List 1 before 2 before 3)
74	
75	      // Capture surrounding context for the description
76	      const ctxStart = Math.max(0, m.index - 90);
77	      const ctxEnd   = Math.min(section.text.length, m.index + raw.length + 90);
78	      const desc = section.text
79	        .slice(ctxStart, ctxEnd)
80	        .replace(/\n/g, ' ')
81	        .replace(/\s{2,}/g, ' ')
82	        .trim()
83	        .slice(0, 130);
84	
85	      lookup[code] = {
86	        list:        section.list,
87	        rate:        section.rate,
88	        description: desc,
89	      };
90	    }
91	  }
92	
93	  return lookup;
94	}
95	
96	/**
97	 * Detect list sections in the document and return [{list, rate, text}].
98	 * Falls back to treating the whole document as List 3 if no markers are found.
99	 *
100	 * @param {string} text
101	 * @returns {Array<{list:string, rate:number, text:string}>}
102	 */
103	function detectSections(text) {
104	  // Ordered from highest-priority list to lowest so the first match wins
105	  // when multiple markers appear close together.
106	  const MARKERS = [
107	    { re: /\bList\s*4\s*A\b/i,   list: 'List 4A', rate: 7.5 },
108	    { re: /\bAnnex\s*[Ee]\b/i,   list: 'List 4A', rate: 7.5 }, // some PDFs use Annex E
109	    { re: /\bList\s*3\b/i,       list: 'List 3',  rate: 25 },
110	    { re: /\bAnnex\s*[Cc]\b/i,   list: 'List 3',  rate: 25 },
111	    { re: /\bList\s*2\b/i,       list: 'List 2',  rate: 25 },
112	    { re: /\bAnnex\s*[Bb]\b/i,   list: 'List 2',  rate: 25 },
113	    { re: /\bList\s*1\b/i,       list: 'List 1',  rate: 25 },
114	    { re: /\bAnnex\s*[Aa]\b/i,   list: 'List 1',  rate: 25 },
115	  ];
116	
117	  /** @type {Array<{pos:number, list:string, rate:number}>} */
118	  const positions = [];
119	
120	  for (const m of MARKERS) {
121	    const re = new RegExp(m.re.source, 'gi');
122	    let hit;
123	    while ((hit = re.exec(text)) !== null) {
124	      // Avoid duplicate consecutive positions for the same list
125	      const last = positions[positions.length - 1];
126	      if (!last || last.list !== m.list || hit.index - last.pos > 2000) {
127	        positions.push({ pos: hit.index, list: m.list, rate: m.rate });
128	      }
129	    }
130	  }
131	
132	  if (positions.length === 0) {
133	    // No section markers — assume the whole doc is List 3 (largest/most common list)
134	    return [{ list: 'List 3', rate: 25, text }];
135	  }
136	
137	  positions.sort((a, b) => a.pos - b.pos);
138	
139	  return positions.map((p, i) => ({
140	    list: p.list,
141	    rate: p.rate,
142	    text: text.slice(p.pos, positions[i + 1]?.pos ?? text.length),
143	  }));
144	}
145	
146	/**
147	 * Normalize an HTS code to 10-digit form.
148	 * Examples:
149	 *   "8471.30.01"   → "8471.30.0100"
150	 *   "9503.00.0090" → "9503.00.0090" (unchanged)
151	 *
152	 * @param {string} code
153	 * @returns {string}
154	 */
155	function normalizeHtsCode(code) {
156	  const parts = code.split('.');
157	  if (parts.length !== 3) return code;
158	  return `${parts[0]}.${parts[1]}.${parts[2].padEnd(4, '0')}`;
159	}
160	
161	/**
162	 * Look up a single HTS code in the stored lookup object.
163	 * Uses exact match first, then falls back to 8-digit prefix match.
164	 *
165	 * @param {Record<string,{list:string,rate:number,description:string}>} lookup
166	 * @param {string} htsCode  HTS code (8 or 10 digits)
167	 * @returns {{ list:string, rate:number, description:string } | null}
168	 */
169	function lookupCode(lookup, htsCode) {
170	  if (!lookup || !htsCode) return null;
171	  const code = normalizeHtsCode(htsCode.trim());
172	
173	  // 1. Exact 10-digit match
174	  if (lookup[code]) return lookup[code];
175	
176	  // 2. 8-digit prefix match (NNNN.NN.** → find any entry with that prefix)
177	  const prefix8 = code.slice(0, 7); // "NNNN.NN"
178	  const hit = Object.keys(lookup).find(k => k.startsWith(prefix8));
179	  if (hit) return lookup[hit];
180	
181	  return null;
182	}
183	
184	module.exports = { parsePdf, parseText, normalizeHtsCode, lookupCode };
