1	/**
2	 * Trump 2025 reciprocal-tariff lookup.
3	 *
4	 * Stored shape (in app_settings under key "trump_2025_tariffs"):
5	 *
6	 *   [
7	 *     { country: "China",   rate: 34 },
8	 *     { country: "Vietnam", rate: 46 },
9	 *     { country: "India",   rate: 26 },
10	 *     ...
11	 *   ]
12	 *
13	 * `country` is matched case-insensitively against either the exact name or any
14	 * known alias (e.g. "PRC" / "Mainland China" both match "China"). Whitespace
15	 * and punctuation are normalized so "United States of America" hits "USA".
16	 *
17	 * The list is hand-maintained by admins via the editor UI because Trump 2025
18	 * rates change on political timelines, not on a published schedule. Keeping it
19	 * in app_settings makes updates a one-click affair.
20	 */
21	
22	'use strict';
23	
24	/**
25	 * A few hand-curated aliases for countries whose FOB-country labels in our
26	 * system don't match the canonical USTR proclamation name. Keep this short —
27	 * the admin should add the country under whichever name they use in FOB Country
28	 * dropdowns, not rely on the alias table.
29	 */
30	const ALIASES = {
31	  'china':                            'china',
32	  'p.r.c.':                           'china',
33	  'prc':                              'china',
34	  'peoples republic of china':        'china',
35	  'mainland china':                   'china',
36	  'usa':                              'united states',
37	  'u.s.a.':                           'united states',
38	  'united states of america':         'united states',
39	  'south korea':                      'korea',
40	  'republic of korea':                'korea',
41	  'korea, republic of':               'korea',
42	  'vietnam':                          'vietnam',
43	  'viet nam':                         'vietnam',
44	  'taiwan':                           'taiwan',
45	  'taipei':                           'taiwan',
46	  'chinese taipei':                   'taiwan',
47	};
48	
49	/**
50	 * Normalize a country name for matching: lowercased, punctuation stripped,
51	 * whitespace collapsed, then alias-resolved.
52	 */
53	function normalizeCountry(name) {
54	  if (!name || typeof name !== 'string') return '';
55	  const stripped = name
56	    .toLowerCase()
57	    .replace(/[.,'"`]/g, '')
58	    .replace(/\s+/g, ' ')
59	    .trim();
60	  return ALIASES[stripped] ?? stripped;
61	}
62	
63	/**
64	 * Validate a Trump 2025 tariff list payload.
65	 * Returns the cleaned list on success; throws on malformed input.
66	 *
67	 * @param {unknown} input
68	 * @returns {Array<{country: string, rate: number}>}
69	 */
70	function parseList(input) {
71	  if (!Array.isArray(input)) throw new Error('payload must be an array');
72	  const out = [];
73	  const seen = new Set();
74	  for (const entry of input) {
75	    if (!entry || typeof entry !== 'object') {
76	      throw new Error('each entry must be an object { country, rate }');
77	    }
78	    const country = typeof entry.country === 'string' ? entry.country.trim() : '';
79	    if (!country) throw new Error('each entry must have a non-empty country');
80	
81	    const rateNum = typeof entry.rate === 'number' ? entry.rate : parseFloat(entry.rate);
82	    if (!Number.isFinite(rateNum) || rateNum < 0 || rateNum > 500) {
83	      throw new Error(`invalid rate for country "${country}" (must be a number 0–500)`);
84	    }
85	
86	    const key = normalizeCountry(country);
87	    if (seen.has(key)) throw new Error(`duplicate country "${country}"`);
88	    seen.add(key);
89	
90	    out.push({ country, rate: rateNum });
91	  }
92	  return out;
93	}
94	
95	/**
96	 * Look up the Trump 2025 rate for the given FOB country.
97	 *
98	 * @param {Array<{country:string, rate:number}>} list
99	 * @param {string} country
100	 * @returns {{ found:boolean, country:string|null, rate:number|null, matchedAs:string|null }}
101	 */
102	function lookupRate(list, country) {
103	  const empty = { found: false, country: null, rate: null, matchedAs: null };
104	  if (!Array.isArray(list) || list.length === 0 || !country) return empty;
105	
106	  const target = normalizeCountry(country);
107	  if (!target) return empty;
108	
109	  for (const entry of list) {
110	    if (normalizeCountry(entry.country) === target) {
111	      return { found: true, country: entry.country, rate: entry.rate, matchedAs: target };
112	    }
113	  }
114	  return empty;
115	}
116	
117	module.exports = { normalizeCountry, parseList, lookupRate };
